/* =============================================================================
   AURA ALPHA -- Admin Usage Analytics Dashboard
   Platform funnel metrics, tier distribution, recent activity, referral stats.
   LAUNCH DAY dashboard at top with 30s auto-refresh for real-time monitoring.
   Wired to real backend endpoints.
   ============================================================================= */
import { useState, useEffect, useCallback, useRef } from 'react';
import LoadingState from '../components/LoadingState';
import ExportBar from '../components/ExportBar';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import { SkeletonMetricRow, SkeletonChart as SkeletonKitChart } from '../components/SkeletonKit';
import { tokens } from '../styles/tokens';
import s from './AdminAnalyticsPage.module.css';

// ── Design tokens (kept for dynamic color references) ────────────────────────
const T = {
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  textSec: tokens.color.textSecondary,
};

// ── Auth helper ──────────────────────────────────────────────────────────────
function authHeaders() {
  try {
    const token = localStorage.getItem('aura_token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  } catch { return {}; }
}

// ── Fetch helper (returns json or null) ─────────────────────────────────────
async function apiFetch(path, opts = {}) {
  try {
    const res = await fetch(`${getApiBase()}${path}`, {
      headers: { 'Content-Type': 'application/json', ...authHeaders() },
      ...opts,
    });
    if (!res.ok) return null;
    return await res.json();
  } catch {
    return null;
  }
}

// ── Number formatting helpers ────────────────────────────────────────────────
const fmtNum = (n) => (n ?? 0).toLocaleString('en-US');
const fmtPct = (n) => `${(n ?? 0).toFixed(1)}%`;
const fmtUsd = (cents) => {
  const dollars = (cents ?? 0) / 100;
  if (dollars >= 1000) return `$${(dollars / 1000).toFixed(1)}k`;
  return `$${dollars.toFixed(2)}`;
};
const fmtDollars = (n) => {
  if ((n ?? 0) >= 1000) return `$${((n ?? 0) / 1000).toFixed(1)}k`;
  return `$${(n ?? 0).toLocaleString('en-US')}`;
};
const fmtDate = (d) => {
  if (!d) return '--';
  try {
    const dt = typeof d === 'number' ? new Date(d * 1000) : new Date(d);
    return dt.toLocaleString('en-US', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
  } catch { return '--'; }
};
const fmtTime = (d) => {
  if (!d) return '--';
  try {
    const dt = typeof d === 'number' ? new Date(d * 1000) : new Date(d);
    return dt.toLocaleString('en-US', { hour: '2-digit', minute: '2-digit' });
  } catch { return '--'; }
};

// ── Reusable card wrapper ────────────────────────────────────────────────────
function Card({ children, className, style, ...props }) {
  return (
    <div className={`${s.card} ${className || ''}`} style={style} {...props}>
      {children}
    </div>
  );
}

// ── KPI Stat Card ────────────────────────────────────────────────────────────
function KpiCard({ label, value, sub, subColor }) {
  return (
    <Card className={s.kpiCard}>
      <div className={s.kpiLabel}>{label}</div>
      <div className={s.kpiValue}>{value}</div>
      {sub != null && (
        <div className={s.kpiSub} style={{ color: subColor || undefined }}>
          {sub}
        </div>
      )}
    </Card>
  );
}

// ── Funnel Bar ───────────────────────────────────────────────────────────────
function FunnelBar({ label, count, pct, maxCount, color }) {
  const width = maxCount > 0 ? Math.max((count / maxCount) * 100, 4) : 4;
  return (
    <div className={s.funnelRow}>
      <div className={s.funnelHeader}>
        <span className={s.funnelLabel}>{label}</span>
        <span className={s.funnelCount}>
          {fmtNum(count)} <span className={s.funnelPct}>({fmtPct(pct)})</span>
        </span>
      </div>
      <div className={s.funnelTrack}>
        <div
          className={s.funnelFill}
          style={{
            width: `${width}%`,
            background: `linear-gradient(90deg, ${color} 0%, ${color}88 100%)`,
          }}
        >
          {width > 20 && (
            <span className={s.funnelFillLabel}>{fmtNum(count)}</span>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Tier Distribution Bar (horizontal) ───────────────────────────────────────
const TIER_COLORS = {
  free: T.textSec,
  explorer: T.textSec,
  starter_47: T.blue,
  starter: T.blue,
  trader: T.blue,
  professional_197: T.green,
  professional: T.green,
  pro: T.green,
  power_497: T.amber,
  power: T.amber,
  elite_997: T.purple,
  elite: T.purple,
  institutional: T.purple,
};

function TierBar({ tier, label, count, pct, maxCount }) {
  const width = maxCount > 0 ? Math.max((count / maxCount) * 100, 3) : 3;
  const color = TIER_COLORS[tier] || TIER_COLORS[tier?.toLowerCase()] || T.blue;
  return (
    <div className={s.tierRow}>
      <div className={s.tierLabel}>{label}</div>
      <div className={s.tierTrack}>
        <div
          className={s.tierFill}
          style={{ width: `${width}%`, background: color }}
        />
      </div>
      <div className={s.tierCount}>
        {fmtNum(count)} <span className={s.tierPctDim}>({fmtPct(pct)})</span>
      </div>
    </div>
  );
}

// ── Action badge ─────────────────────────────────────────────────────────────
function ActionBadge({ action }) {
  const map = {
    signup:       { bg: `${T.blue}22`, color: T.blue, label: 'Signup' },
    upgrade:      { bg: `${T.green}22`, color: T.green, label: 'Upgrade' },
    downgrade:    { bg: `${T.amber}22`, color: T.amber, label: 'Downgrade' },
    cancellation: { bg: `${T.red}22`, color: T.red, label: 'Cancelled' },
    payment:      { bg: `${T.green}22`, color: T.green, label: 'Payment' },
    refund:       { bg: `${T.red}22`, color: T.red, label: 'Refund' },
  };
  const cfg = map[action] || { bg: `${T.textSec}22`, color: T.textSec, label: action };
  return (
    <span className={s.badge} style={{ background: cfg.bg, color: cfg.color }}>
      {cfg.label}
    </span>
  );
}


// =============================================================================
//  LAUNCH DAY DASHBOARD SECTION
// =============================================================================

function LaunchDashboard({ data, loading }) {
  const ld = data || {};
  const funnel = ld.funnel || {};
  const revenueByTier = ld.revenue_by_tier || [];
  const hourlySignups = ld.hourly_signups || [];
  const dailySignups = ld.daily_signups || [];
  const recentSignups = ld.recent_signups || [];

  const totalUsers = ld.total_users || 0;
  const signupsToday = ld.signups_today || 0;
  const foundingMembers = ld.founding_members || 0;
  const foundingRemaining = ld.founding_remaining ?? 100;
  const activeTrials = ld.active_trials || 0;
  const payingSubs = ld.paying_subscribers || 0;
  const mrr = ld.mrr || 0;
  const arr = ld.arr || 0;

  // Founding spot fill percentage
  const foundingFillPct = Math.min(100, ((100 - foundingRemaining) / 100) * 100);

  // Max daily signup count for chart scaling
  const maxDailyCount = Math.max(...dailySignups.map(d => d.count), 1);
  const maxHourlyCount = Math.max(...hourlySignups.map(h => h.count), 1);

  // Max tier revenue for bar scaling
  const maxTierRevenue = Math.max(...revenueByTier.map(t => t.monthly_revenue || 0), 1);

  // Use hourly if we have today's data, otherwise daily
  const useHourly = hourlySignups.length > 0;
  const chartData = useHourly ? hourlySignups : dailySignups;
  const chartMax = useHourly ? maxHourlyCount : maxDailyCount;

  return (
    <div className={s.launchSection}>
      {/* ── Header ────────────────────────────────────────── */}
      <div className={s.launchHeader}>
        <div className={s.launchTitleRow}>
          <h1 className={s.launchTitle}>Launch Day</h1>
          <span className={s.liveBadge}>
            <span className={s.liveDot} />
            Live
          </span>
        </div>
        <div className={s.launchRefresh}>
          {loading ? 'Refreshing...' : `Updated ${fmtTime(ld.updated_at)}`}
          {' | 30s auto-refresh'}
        </div>
      </div>

      {/* ── Top KPI Row ───────────────────────────────────── */}
      <div className={s.launchKpiGrid}>
        {/* MRR Hero Card (spans 2 cols) */}
        <div className={s.mrrCard}>
          <div className={s.launchKpiLabel}>Monthly Recurring Revenue</div>
          <div className={s.launchKpiValueHero} style={{ color: T.green }}>
            {fmtDollars(mrr)}
          </div>
          <div className={s.mrrRow} style={{ marginTop: 12 }}>
            <div>
              <div className={s.mrrArrLabel}>ARR</div>
              <div className={s.mrrArrValue}>{fmtDollars(arr)}</div>
            </div>
            <div>
              <div className={s.mrrArrLabel}>Paying Subscribers</div>
              <div className={s.mrrArrValue} style={{ color: T.green }}>{fmtNum(payingSubs)}</div>
            </div>
          </div>
        </div>

        {/* Signups Today */}
        <div className={s.launchKpiCard} style={{ borderTop: `3px solid ${T.blue}` }}>
          <div className={s.launchKpiLabel}>Signups Today</div>
          <div className={s.launchKpiValueHero} style={{ color: T.blue }}>
            {fmtNum(signupsToday)}
          </div>
          <div className={s.launchKpiSub}>real-time counter</div>
        </div>

        {/* Total Users */}
        <div className={s.launchKpiCard}>
          <div className={s.launchKpiLabel}>Total Users</div>
          <div className={s.launchKpiValue}>{fmtNum(totalUsers)}</div>
          <div className={s.launchKpiSub}>all-time registrations</div>
        </div>

        {/* Founding Members */}
        <div className={s.launchKpiCard} style={{ borderTop: `3px solid ${T.amber}` }}>
          <div className={s.launchKpiLabel}>Founding Members</div>
          <div className={s.launchKpiValue} style={{ color: T.amber }}>{fmtNum(foundingMembers)}</div>
          <div className={s.foundingProgress}>
            <div className={s.foundingProgressBar}>
              <div className={s.foundingProgressFill} style={{ width: `${foundingFillPct}%` }} />
            </div>
            <div className={s.foundingProgressLabel}>
              {foundingRemaining} spots remaining
            </div>
          </div>
        </div>

        {/* Founding Spots Remaining */}
        <div className={s.launchKpiCard}>
          <div className={s.launchKpiLabel}>Founding Spots Left</div>
          <div className={s.launchKpiValue} style={{ color: foundingRemaining <= 10 ? T.red : foundingRemaining <= 30 ? T.amber : T.green }}>
            {fmtNum(foundingRemaining)}
          </div>
          <div className={s.launchKpiSub}>of 100 total</div>
        </div>

        {/* Active Trials */}
        <div className={s.launchKpiCard}>
          <div className={s.launchKpiLabel}>Active Trials</div>
          <div className={s.launchKpiValue} style={{ color: T.purple }}>{fmtNum(activeTrials)}</div>
          <div className={s.launchKpiSub}>14-day free trials</div>
        </div>
      </div>

      {/* ── Two-column: Conversion Funnel + Revenue by Tier ── */}
      <div className={s.launchTwoCol}>

        {/* Conversion Funnel */}
        <Card>
          <div className={s.sectionTitle}>Conversion Funnel</div>

          {/* Registrations */}
          <div className={s.launchFunnelStage}>
            <div className={s.launchFunnelIcon} style={{ background: `${T.blue}18`, color: T.blue }}>
              1
            </div>
            <div className={s.launchFunnelInfo}>
              <div className={s.launchFunnelName}>Registrations</div>
              <div className={s.launchFunnelBar}>
                <div className={s.launchFunnelBarFill} style={{ width: '100%', background: T.blue }} />
              </div>
            </div>
            <div className={s.launchFunnelStats}>
              <div className={s.launchFunnelCount}>{fmtNum(funnel.registrations)}</div>
              <div className={s.launchFunnelPct}>100%</div>
            </div>
          </div>

          <div className={s.launchFunnelArrow}>
            <div className={s.launchFunnelArrowText}>{fmtPct(funnel.reg_to_trial_pct)} conversion</div>
          </div>

          {/* Active Trials */}
          <div className={s.launchFunnelStage}>
            <div className={s.launchFunnelIcon} style={{ background: `${T.purple}18`, color: T.purple }}>
              2
            </div>
            <div className={s.launchFunnelInfo}>
              <div className={s.launchFunnelName}>Active Trials</div>
              <div className={s.launchFunnelBar}>
                <div
                  className={s.launchFunnelBarFill}
                  style={{
                    width: `${funnel.registrations > 0 ? Math.max((funnel.trial_active / funnel.registrations) * 100, 3) : 3}%`,
                    background: T.purple,
                  }}
                />
              </div>
            </div>
            <div className={s.launchFunnelStats}>
              <div className={s.launchFunnelCount}>{fmtNum(funnel.trial_active)}</div>
              <div className={s.launchFunnelPct}>{fmtPct(funnel.reg_to_trial_pct)}</div>
            </div>
          </div>

          <div className={s.launchFunnelArrow}>
            <div className={s.launchFunnelArrowText}>{fmtPct(funnel.trial_to_paid_pct)} conversion</div>
          </div>

          {/* Paid Subscribers */}
          <div className={s.launchFunnelStage}>
            <div className={s.launchFunnelIcon} style={{ background: `${T.green}18`, color: T.green }}>
              3
            </div>
            <div className={s.launchFunnelInfo}>
              <div className={s.launchFunnelName}>Paid Subscribers</div>
              <div className={s.launchFunnelBar}>
                <div
                  className={s.launchFunnelBarFill}
                  style={{
                    width: `${funnel.registrations > 0 ? Math.max((funnel.paid_subscriber / funnel.registrations) * 100, 3) : 3}%`,
                    background: T.green,
                  }}
                />
              </div>
            </div>
            <div className={s.launchFunnelStats}>
              <div className={s.launchFunnelCount}>{fmtNum(funnel.paid_subscriber)}</div>
              <div className={s.launchFunnelPct}>{fmtPct(funnel.reg_to_paid_pct)}</div>
            </div>
          </div>

          <div className={s.funnelFooter} style={{ marginTop: 16 }}>
            End-to-end: {fmtPct(funnel.reg_to_paid_pct)} registration-to-paid
          </div>
        </Card>

        {/* Revenue by Tier */}
        <Card>
          <div className={s.sectionTitle}>Revenue by Tier</div>
          {revenueByTier.length === 0 ? (
            <div style={{ color: T.textSec, fontSize: 13, padding: '20px 0', textAlign: 'center' }}>
              No paid subscribers yet
            </div>
          ) : (
            revenueByTier.map((t) => {
              const barWidth = maxTierRevenue > 0
                ? Math.max((t.monthly_revenue / maxTierRevenue) * 100, 5) : 5;
              const color = TIER_COLORS[t.tier] || TIER_COLORS[t.tier?.toLowerCase()] || T.blue;
              return (
                <div key={t.tier} className={s.launchTierRow}>
                  <div className={s.launchTierName}>{t.label}</div>
                  <div className={s.launchTierCount}>{fmtNum(t.count)} users</div>
                  <div className={s.launchTierBarWrap}>
                    <div
                      className={s.launchTierBarFill}
                      style={{ width: `${barWidth}%`, background: color }}
                    >
                      {barWidth > 25 && (
                        <span className={s.launchTierBarLabel}>{fmtDollars(t.monthly_revenue)}/mo</span>
                      )}
                    </div>
                  </div>
                  <div className={s.launchTierRevenue} style={{ color }}>
                    {fmtDollars(t.monthly_revenue)}/mo
                  </div>
                </div>
              );
            })
          )}

          {revenueByTier.length > 0 && (
            <div style={{ marginTop: 16, paddingTop: 12, borderTop: '1px solid rgba(255,255,255,0.06)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 12, color: T.textSec, textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                  Total MRR
                </span>
                <span style={{ fontSize: 20, fontWeight: 800, fontFamily: "'JetBrains Mono', monospace", color: T.green }}>
                  {fmtDollars(mrr)}/mo
                </span>
              </div>
            </div>
          )}
        </Card>
      </div>

      {/* ── Signup Timeline + Recent Signups ────────────── */}
      <div className={s.launchTwoCol}>

        {/* Signup Timeline Chart */}
        <Card>
          <div className={s.sectionTitle}>
            {useHourly ? 'Signups Today (by hour)' : 'Signups (last 14 days)'}
          </div>
          {chartData.length === 0 ? (
            <div style={{ color: T.textSec, fontSize: 13, padding: '20px 0', textAlign: 'center' }}>
              No signups recorded yet
            </div>
          ) : (
            <>
              <div className={s.timelineChart}>
                {chartData.map((item, i) => {
                  const height = chartMax > 0
                    ? Math.max((item.count / chartMax) * 100, 4) : 4;
                  const label = useHourly
                    ? `${item.hour}:00 - ${item.count} signup${item.count !== 1 ? 's' : ''}`
                    : `${item.date} - ${item.count} signup${item.count !== 1 ? 's' : ''}`;
                  return (
                    <div
                      key={i}
                      className={s.timelineBar}
                      style={{
                        height: `${height}%`,
                        background: `linear-gradient(180deg, ${T.blue} 0%, ${T.blue}44 100%)`,
                      }}
                      data-tooltip={label}
                    />
                  );
                })}
              </div>
              <div className={s.timelineLabels}>
                <span className={s.timelineLabel}>
                  {useHourly
                    ? (chartData[0]?.hour || '00') + ':00'
                    : chartData[0]?.date || ''
                  }
                </span>
                <span className={s.timelineLabel}>
                  {useHourly
                    ? (chartData[chartData.length - 1]?.hour || '23') + ':00'
                    : chartData[chartData.length - 1]?.date || ''
                  }
                </span>
              </div>
            </>
          )}
        </Card>

        {/* Recent Signups Feed */}
        <Card>
          <div className={s.sectionTitle}>Recent Signups</div>
          {recentSignups.length === 0 ? (
            <div style={{ color: T.textSec, fontSize: 13, padding: '20px 0', textAlign: 'center' }}>
              No signups yet
            </div>
          ) : (
            recentSignups.slice(0, 12).map((signup, i) => (
              <div key={i} className={s.recentSignupRow}>
                <span className={s.recentSignupEmail}>{signup.email}</span>
                {signup.is_founding && (
                  <span className={s.foundingBadge}>Founding</span>
                )}
                <span className={s.badge} style={{
                  background: `${TIER_COLORS[signup.tier] || TIER_COLORS[signup.tier?.toLowerCase()] || T.textSec}18`,
                  color: TIER_COLORS[signup.tier] || TIER_COLORS[signup.tier?.toLowerCase()] || T.textSec,
                  fontSize: 9,
                  padding: '2px 8px',
                }}>
                  {signup.tier || 'free'}
                </span>
                <span className={s.recentSignupTime}>{fmtTime(signup.created_at)}</span>
              </div>
            ))
          )}
        </Card>
      </div>
    </div>
  );
}


// ── Main Page Component ──────────────────────────────────────────────────────
export default function AdminAnalyticsPage() {
  usePageTitle('Admin Analytics');

  // Existing analytics state
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Launch dashboard state (separate fetch, 30s refresh)
  const [launchData, setLaunchData] = useState(null);
  const [launchLoading, setLaunchLoading] = useState(true);
  const launchIntervalRef = useRef(null);

  // Additional data sources
  const [signupFunnel, setSignupFunnel] = useState(null);
  const [subHealth, setSubHealth] = useState(null);
  const [revenueData, setRevenueData] = useState(null);

  // ── Fetch existing analytics (60s refresh) ─────────────
  const fetchData = useCallback(async () => {
    try {
      setLoading(true);

      // Fetch analytics, signup funnel, subscription health, and revenue in parallel
      const [analyticsRes, funnelRes, subRes, revRes] = await Promise.all([
        apiFetch('/admin/analytics'),
        apiFetch('/admin/signup-funnel'),
        apiFetch('/admin/subscription-health'),
        apiFetch('/admin/revenue'),
      ]);

      if (analyticsRes) {
        setData(analyticsRes);
        setError(null);
      } else {
        setError('Failed to fetch analytics');
      }

      if (funnelRes) setSignupFunnel(funnelRes);
      if (subRes) setSubHealth(subRes);
      if (revRes) setRevenueData(revRes);
    } catch (err) {
      console.warn('Admin analytics fetch failed:', err.message);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  // ── Fetch launch dashboard (30s refresh) ───────────────
  const fetchLaunch = useCallback(async () => {
    try {
      setLaunchLoading(true);
      const json = await apiFetch('/admin/launch-dashboard');
      if (json) setLaunchData(json);
    } catch (err) {
      console.warn('Launch dashboard fetch failed:', err.message);
    } finally {
      setLaunchLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    fetchLaunch();

    const analyticsIv = setInterval(fetchData, 60_000);
    launchIntervalRef.current = setInterval(fetchLaunch, 30_000);

    return () => {
      clearInterval(analyticsIv);
      if (launchIntervalRef.current) clearInterval(launchIntervalRef.current);
    };
  }, [fetchData, fetchLaunch]);

  // Build unified data from multiple endpoints
  const d = data || {};

  // KPIs: merge analytics endpoint with subscription health and revenue
  const kpis = {
    total_users: d.kpis?.total_users ?? subHealth?.total_users ?? 0,
    total_users_growth_pct: d.kpis?.total_users_growth_pct ?? d.kpis?.growth_pct ?? 0,
    active_users_7d: d.kpis?.active_users_7d ?? d.kpis?.active_users ?? 0,
    paid_subscribers: d.kpis?.paid_subscribers ?? subHealth?.active_subscribers ?? subHealth?.active ?? 0,
    paid_conversion_pct: d.kpis?.paid_conversion_pct ?? subHealth?.conversion_rate ?? 0,
    mrr_cents: d.kpis?.mrr_cents ?? (revenueData?.mrr != null ? Math.round(revenueData.mrr * 100) : 0),
    churn_rate_pct: d.kpis?.churn_rate_pct ?? subHealth?.churn_rate ?? subHealth?.churn ?? 0,
    arpu_cents: d.kpis?.arpu_cents ?? (revenueData?.arpu != null ? Math.round(revenueData.arpu * 100) : 0),
  };

  // Funnel: prefer signup-funnel endpoint, fall back to analytics
  const rawFunnel = signupFunnel?.funnel ?? signupFunnel?.stages ?? d.funnel ?? {};
  const funnel = Array.isArray(rawFunnel) ? {
    signed_up: rawFunnel[0]?.count ?? rawFunnel[0]?.value ?? 0,
    activated: rawFunnel[1]?.count ?? rawFunnel[1]?.value ?? 0,
    trial_started: rawFunnel[2]?.count ?? rawFunnel[2]?.value ?? 0,
    subscribed: rawFunnel[3]?.count ?? rawFunnel[3]?.value ?? 0,
    retained: rawFunnel[4]?.count ?? rawFunnel[4]?.value ?? 0,
  } : {
    signed_up: rawFunnel.signed_up ?? rawFunnel.registrations ?? signupFunnel?.totals?.registrations ?? 0,
    activated: rawFunnel.activated ?? signupFunnel?.totals?.activated ?? 0,
    trial_started: rawFunnel.trial_started ?? signupFunnel?.totals?.trial_started ?? 0,
    subscribed: rawFunnel.subscribed ?? signupFunnel?.totals?.subscribed ?? signupFunnel?.totals?.paid ?? 0,
    retained: rawFunnel.retained ?? 0,
  };

  // Tiers: prefer subscription health, fall back to analytics
  const tiers = d.tier_distribution ?? subHealth?.plan_distribution ?? subHealth?.plans ?? [];
  const activity = d.recent_activity ?? [];
  const refs = d.referral_stats ?? {};

  const funnelStages = [
    { key: 'signed_up',     label: 'Signed Up',    color: T.blue },
    { key: 'activated',     label: 'Activated',     color: T.purple },
    { key: 'trial_started', label: 'Trial Started', color: T.amber },
    { key: 'subscribed',    label: 'Subscribed',    color: T.green },
    { key: 'retained',      label: 'Retained (2mo+)', color: T.green },
  ];
  const funnelMax = funnel.signed_up || 1;

  const tierMax = tiers.length > 0 ? Math.max(...tiers.map(t => t.count ?? t.subscribers ?? 0), 1) : 1;

  // ── Render ──────────────────────────────────────────────────────────────────
  return (
    <div className={s.page}>

      {/* ══════════════════════════════════════════════════════
          LAUNCH DAY DASHBOARD (top of page, 30s auto-refresh)
          ══════════════════════════════════════════════════════ */}
      <LaunchDashboard data={launchData} loading={launchLoading} />

      {/* ── Section Divider ─────────────────────────────────── */}
      <div className={s.sectionDivider}>Platform Analytics (Full)</div>

      {/* ── Header ──────────────────────────────────────────────── */}
      <div className={s.header}>
        <div className={s.headerLeft}>
          <h1 className={s.title}>Platform Analytics</h1>
          <span className={s.adminBadge}>Admin</span>
          {error && !data && <span className={s.demoLabel}>(no data)</span>}
        </div>
        <div className={s.updatedAt}>
          {loading ? <><SkeletonMetricRow count={2} /><div style={{ marginTop: 8 }}><SkeletonKitChart height={80} /></div></> : `Updated ${fmtDate(d.updated_at)}`}
        </div>
      </div>

      {/* ── KPI Stats Cards ─────────────────────────────────────── */}
      <div className={s.kpiGrid}>
        <KpiCard
          label="Total Users"
          value={fmtNum(kpis.total_users)}
          sub={`${kpis.total_users_growth_pct >= 0 ? '+' : ''}${fmtPct(kpis.total_users_growth_pct)} (30d)`}
          subColor={kpis.total_users_growth_pct >= 0 ? T.green : T.red}
        />
        <KpiCard
          label="Active Users (7d)"
          value={fmtNum(kpis.active_users_7d)}
        />
        <KpiCard
          label="Paid Subscribers"
          value={fmtNum(kpis.paid_subscribers)}
          sub={`${fmtPct(kpis.paid_conversion_pct)} conversion`}
          subColor={T.green}
        />
        <KpiCard
          label="MRR"
          value={fmtUsd(kpis.mrr_cents)}
          sub="Monthly Recurring Revenue"
        />
        <KpiCard
          label="Churn Rate"
          value={fmtPct(kpis.churn_rate_pct)}
          sub="30-day rolling"
          subColor={kpis.churn_rate_pct > 5 ? T.red : kpis.churn_rate_pct > 3 ? T.amber : T.green}
        />
        <KpiCard
          label="ARPU"
          value={fmtUsd(kpis.arpu_cents)}
          sub="Avg Revenue / Paid User"
        />
      </div>

      {/* ── Two-column layout: Funnel + Tier Distribution ─────── */}
      <div className={s.twoCol}>

        {/* Conversion Funnel */}
        <Card className={s.twoColCard}>
          <div className={s.sectionTitle}>Conversion Funnel</div>
          {funnelStages.map((stage) => {
            const count = funnel[stage.key] || 0;
            const pct = funnelMax > 0 ? (count / funnelMax) * 100 : 0;
            return (
              <FunnelBar
                key={stage.key}
                label={stage.label}
                count={count}
                pct={pct}
                maxCount={funnelMax}
                color={stage.color}
              />
            );
          })}
          <div className={s.funnelFooter}>
            End-to-end: {funnelMax > 0 ? fmtPct((funnel.retained || 0) / funnelMax * 100) : '0%'} of signups retained
          </div>
        </Card>

        {/* Tier Distribution */}
        <Card className={s.twoColCard}>
          <div className={s.sectionTitle}>Tier Distribution</div>
          {tiers.length > 0 ? (
            tiers.map((t, i) => (
              <TierBar
                key={t.tier ?? t.name ?? t.plan ?? i}
                tier={t.tier ?? t.name ?? t.plan}
                label={t.label ?? t.name ?? t.plan ?? `Tier ${i + 1}`}
                count={t.count ?? t.subscribers ?? 0}
                pct={t.pct ?? (tierMax > 0 ? ((t.count ?? t.subscribers ?? 0) / tierMax) * 100 : 0)}
                maxCount={tierMax}
              />
            ))
          ) : (
            <div style={{ color: T.textSec, fontSize: 13, padding: '20px 0', textAlign: 'center' }}>
              No tier distribution data
            </div>
          )}
          {tiers.filter(t => (t.tier ?? t.name ?? '') !== 'free').length > 0 && (
            <div className={s.tierLegend}>
              {tiers.filter(t => (t.tier ?? t.name ?? '') !== 'free').map((t, i) => (
                <div key={t.tier ?? t.name ?? i} className={s.tierLegendItem}>
                  <div className={s.tierLegendDot} style={{ background: TIER_COLORS[t.tier] || TIER_COLORS[t.tier?.toLowerCase()] || T.blue }} />
                  <span className={s.tierLegendLabel}>{t.label ?? t.name ?? t.plan}: {fmtNum(t.count ?? t.subscribers ?? 0)}</span>
                </div>
              ))}
            </div>
          )}
        </Card>
      </div>

      {/* ── Recent Activity Table + Referral Stats ────────────── */}
      <div className={s.activityGrid}>

        {/* Recent Activity */}
        <Card className={s.activityCard}>
          <div className={s.activityHeader}>Recent Activity</div>
          <ExportBar
            data={activity}
            filename='admin-analytics-recent-activity-export'
            columns={['Date', 'User', 'Action', 'Tier', 'Revenue Impact']}
            style={{ padding: '0 20px 12px' }}
          />
          <div className={s.tableWrap}>
            <table className={s.table}>
              <thead>
                <tr>
                  {['Date', 'User', 'Action', 'Tier', 'Revenue Impact'].map(h => (
                    <th key={h} className={s.th}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {activity.length === 0 ? (
                  <tr>
                    <td colSpan={5} className={s.emptyRow}>No recent activity</td>
                  </tr>
                ) : (
                  activity.slice(0, 20).map((row, i) => {
                    const impact = row.revenue_impact_cents || 0;
                    return (
                      <tr key={i} className={i % 2 === 0 ? s.activityRow : s.activityRowAlt}>
                        <td className={s.tdDate}>{fmtDate(row.date)}</td>
                        <td className={s.tdUser}>{row.user || '--'}</td>
                        <td className={s.td}><ActionBadge action={row.action} /></td>
                        <td className={s.tdTier}>{row.tier || '--'}</td>
                        <td
                          className={s.tdImpact}
                          style={{ color: impact > 0 ? T.green : impact < 0 ? T.red : T.textSec }}
                        >
                          {impact > 0 ? '+' : ''}{impact !== 0 ? fmtUsd(impact) : '--'}
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </Card>

        {/* Referral Stats */}
        <Card>
          <div className={s.sectionTitle}>Referral Program</div>

          <div className={s.refBlock}>
            <div className={s.refLabel}>Codes Created</div>
            <div className={s.refValue} style={{ color: T.blue }}>
              {fmtNum(refs.codes_created)}
            </div>
          </div>

          <div className={s.refBlock}>
            <div className={s.refLabel}>Referrals Converted</div>
            <div className={s.refValue} style={{ color: T.green }}>
              {fmtNum(refs.referrals_converted)}
            </div>
            <div className={s.refSub}>
              {refs.codes_created > 0 ? fmtPct((refs.referrals_converted / refs.codes_created) * 100) : '0%'} conversion
            </div>
          </div>

          <div>
            <div className={s.refLabel}>Credits Awarded</div>
            <div className={s.refValue} style={{ color: T.amber }}>
              {fmtUsd(refs.total_credits_awarded_cents)}
            </div>
          </div>

          <div className={s.refNote}>
            <div className={s.refNoteText}>
              Each referral awards <span className={s.refNoteHighlight}>$50</span> credit
              to both referrer and referee upon subscription activation.
            </div>
          </div>
        </Card>
      </div>
    </div>
  );
}
